+        assert!(cx.checkpoint().is_ok());
+
+        // Original snapshot should be unchanged
+        assert_eq!(snapshot.checkpoint_count, 0);
+
+        // New snapshot should reflect updates
+        assert_eq!(cx.checkpoint_state().checkpoint_count, 2);
+    }
